const j = $input.item.json;
const audio = String(j.explicacion_audio_transcrita || '').trim();
const cat = String(j.ticket_categoria || '');
const motor = 'openai_vision';
const RULES = `Sos un asistente para rendiciones de gastos (Argentina). Vas a ver la IMAGEN del comprobante (OCR + interpretación).

Montos (crítico en tickets térmicos / factura A o tique):
- Los totales en ARS suelen ser grandes (5–7 dígitos enteros + centavos). Un error frecuente es "perder" un cero o un dígito en el TOTAL (ej. leer 11103,02 en vez de 111003,02).
- Si el ticket muestra el total como 111003.02 sin separador de miles, el PUNTO son los DECIMALES: es 111.003,02 pesos, NO 11.100,302 ni 1.110.030,2.
- Buscá la línea TOTAL / IMPORTE TOTAL y releé dígito por dígito. Si el mismo importe se repite (ej. junto a Tarjeta / MODO), usá ambas lecturas para validar.
- Si hay desglose AFIP (Subtotal neto gravado + IVA + Impuestos internos / otros tributos), extraé esos tres importes y comprobá que sumen el TOTAL. Si el TOTAL impreso es dudoso pero la suma de líneas claras es coherente, asigná monto_total = esa suma.

Otros:
- Fecha y CUIT del proveedor si figuran.
- No evalúes topes de empresa. Whisper solo para contradicciones obvias con el papel.
- Compliance_Score 0–1 por legibilidad y coherencia interna del comprobante.`;
const ocr_compliance_prompt = `${RULES}

Motor (referencia): ${motor}
Categoría declarada por el empleado: ${cat}
Transcripción voz (Whisper): ${audio || '(sin audio)'}

--- Tarea ---
Analizá la imagen del comprobante.

--- Salida obligatoria ---
Un solo objeto JSON (sin markdown). Claves:
- monto_total (number|null) — total a pagar, número JS con punto decimal
- importe_neto_gravado (number|null) — si hay "subtotal neto gravado" o equivalente
- importe_iva (number|null) — si hay IVA discriminado
- importe_otros_tributos (number|null) — impuestos internos / otros tributos / similar
- moneda (string)
- fecha_factura (YYYY-MM-DD|null)
- CUIT_proveedor (solo dígitos o null)
- Compliance_Score (0-1)
- compliance_observaciones (breve; podés mencionar verificación suma vs TOTAL)
- violaciones (array de strings)
- parser_engine exactamente "openai_vision"
Si no hay desglose, los importe_* en null.`;
return {
  json: { ...j, ocr_compliance_prompt, parser_engine: motor },
  binary: $input.item.binary || {}
};

const idx = $itemIndex;
const base = $('Code — Expandir Tickets').all()[idx].json;
const driveJ = $('Drive — Subir foto').all()[idx]?.json || {};
const visionJ = $('OpenAI — OCR + Compliance (visión)').all()[idx]?.json || {};

function coerceLlmText(m) {
  if (m == null) return '';
  if (typeof m === 'string') return m;
  let t = m.content ?? m.text ?? m.output ?? m.response;
  if (t && typeof t === 'object') {
    t = t.text ?? t.output ?? t.message?.content ?? t.content ?? (Array.isArray(t.generations) ? String(t.generations[0]?.[0]?.text ?? '') : JSON.stringify(t));
  }
  return String(t ?? '');
}

function parseComplianceJson(raw) {
  let s = String(raw || '').trim();
  s = s.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
  if (!s) return null;
  try {
    return JSON.parse(s);
  } catch (e1) {
    try {
      const i = s.indexOf('{');
      const j = s.lastIndexOf('}');
      if (i >= 0 && j > i) return JSON.parse(s.slice(i, j + 1));
    } catch (e2) {}
  }
  try {
    const m = s.match(/\{[\s\S]*\}/);
    if (m) return JSON.parse(m[0]);
  } catch (e3) {}
  return null;
}

function normalizeKeys(o) {
  if (!o || typeof o !== 'object') return {};
  const out = { ...o };
  if (out.monto_total == null && out.montoTotal != null) out.monto_total = out.montoTotal;
  if (out.fecha_factura == null && out.fechaFactura != null) out.fecha_factura = out.fechaFactura;
  if (out.CUIT_proveedor == null && out.cuit_proveedor != null) out.CUIT_proveedor = out.cuit_proveedor;
  if (out.Compliance_Score == null && out.compliance_score != null) out.Compliance_Score = out.compliance_score;
  if (out.importe_neto_gravado == null) {
    const x = out.subtotal_neto_gravado ?? out.subtotal_importe_neto_gravado ?? out.neto_gravado;
    if (x != null) out.importe_neto_gravado = x;
  }
  if (out.importe_iva == null && out.iva != null) out.importe_iva = out.iva;
  if (out.importe_otros_tributos == null) {
    const x =
      out.impuestos_internos ??
      out.importe_impuestos_internos ??
      out.importe_total_otros_tributos ??
      out.otros_tributos;
    if (x != null) out.importe_otros_tributos = x;
  }
  return out;
}

const parsed = parseComplianceJson(coerceLlmText(visionJ));
let ocr = normalizeKeys(parsed) || {};
ocr = {
  monto_total: null,
  moneda: '',
  fecha_factura: null,
  CUIT_proveedor: null,
  Compliance_Score: 0.5,
  compliance_observaciones: '',
  violaciones: [],
  parser_engine: 'openai_vision',
  ...ocr
};

const pe = 'openai_vision';

function normalizeAmount(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;

  const s = String(v).trim();
  if (!s) return null;

  let cleaned = s.replace(/[^\d,\.\-]/g, '');

  if (cleaned.includes(',') && cleaned.includes('.')) {
    cleaned = cleaned.replace(/\./g, '').replace(',', '.');
  } else if (cleaned.includes(',')) {
    cleaned = cleaned.replace(',', '.');
  }

  const n = parseFloat(cleaned);
  return Number.isFinite(n) ? n : null;
}

function pickMontoTotal(ocr) {
  const direct = normalizeAmount(ocr.monto_total);
  const a = normalizeAmount(ocr.importe_neto_gravado);
  const b = normalizeAmount(ocr.importe_iva);
  const c = normalizeAmount(ocr.importe_otros_tributos);
  if (a != null && b != null && c != null && Number.isFinite(a) && Number.isFinite(b) && Number.isFinite(c)) {
    const sum = Math.round((a + b + c) * 100) / 100;
    if (!Number.isFinite(sum) || sum <= 0) return direct;
    if (direct == null) return sum;
    if (Math.abs(sum - direct) > 0.5) return sum;
    return direct;
  }
  return direct;
}

function normalizeCuit(v) {
  if (v === null || v === undefined) return '';
  const s = String(v).replace(/[^\d]/g, '');
  return s || '';
}

let score = Number(ocr.Compliance_Score);
if (!Number.isFinite(score)) score = 0.5;
score = Math.round(Math.min(1, Math.max(0, score)) * 1000) / 1000;

const link = driveJ.webViewLink || driveJ.webContentLink || '';
const idFoto = driveJ.id || driveJ.fileId || '';
const montoDirect = normalizeAmount(ocr.monto_total);
const monto = pickMontoTotal(ocr);
let obsComb = String(ocr.compliance_observaciones || '').slice(0, 2000);
if (
  monto != null &&
  montoDirect != null &&
  Math.abs(monto - montoDirect) > 0.5
) {
  obsComb = (obsComb ? obsComb + ' ' : '') + 'Monto total corregido por suma (neto gravado + IVA + otros tributos): ' + montoDirect + ' → ' + monto + '.';
  obsComb = obsComb.slice(0, 2000);
}

const estado = score < 0.7 ? 'Requiere Revisión Manual' : 'Pendiente';

return {
  json: {
    ...base,
    id_foto_drive: idFoto,
    link_foto_drive: link,
    fecha_ticket_ia: ocr.fecha_factura || '',
    monto_total_ia: monto === null ? '' : monto,
    moneda_ia: ocr.moneda || '',
    cuit_proveedor_ia: normalizeCuit(ocr.CUIT_proveedor),
    Compliance_Score: score,
    Estado: estado,
    estado_compliance_obs: obsComb,
    violaciones_compliance: Array.isArray(ocr.violaciones) ? ocr.violaciones.join('; ') : '',
    parser_engine: pe
  }
};

const all = $input.all();
const j0 = all[0].json;
const ids = all.map(i => i.json.id_rendicion);
const monto_total = all.map(i => {
  const r = i.json;
  const parts = [r.monto_total_ia, r.moneda_ia].filter((v) => v !== null && v !== undefined && v !== '');
  return parts.join(' ').trim();
}).filter(Boolean).join(' · ') || '';
const link_foto_drive = j0.link_foto_drive || (all[0] && all[0].json.link_foto_drive) || '';
const scoreNums = all.map((i) => Number(i.json.Compliance_Score)).filter((n) => Number.isFinite(n));
const batch_compliance_avg = scoreNums.length ? Math.round((scoreNums.reduce((a, b) => a + b, 0) / scoreNums.length) * 1000) / 1000 : '';
const batch_parser_engines = [...new Set(all.map((i) => String(i.json.parser_engine || '').trim()).filter(Boolean))].join('+') || '';
function ensureWebhookSuffix(resumeUrl, suffix) {
  if (!resumeUrl || !suffix) return resumeUrl;
  const s = String(suffix).replace(/^\/+|\/+$/g, '');
  if (resumeUrl.includes('/' + s + '?') || resumeUrl.includes('/' + s + '&') || resumeUrl.endsWith('/' + s)) return resumeUrl;
  const q = resumeUrl.indexOf('?');
  if (q === -1) return resumeUrl + '/' + s;
  return resumeUrl.slice(0, q) + '/' + s + resumeUrl.slice(q);
}
function appendDecision(resumeUrl, decision) {
  if (!resumeUrl) return '';
  const sep = resumeUrl.includes('?') ? '&' : '?';
  return resumeUrl + sep + 'decision=' + encodeURIComponent(decision);
}
const cfg = $('Variables — Config').first().json || {};
const waitSuffix = cfg.wait_webhook_suffix || 'aprobacion-gerente';
const ru = ensureWebhookSuffix($execution.resumeUrl || '', waitSuffix);
return [{
